(319, 1, '2026-03-25 04:18:26', '2026-03-25 04:18:26', '<!-- wp:shortcode -->\n[tienthemes_loop_post post_title=\'LAUNCHPAD RESOURCES\' post_desc=\'LaunchPad supports ideation, establishment and market knowledge. Our content offers relevant learning opportunities to guide founders through the primary stages of building an EdTech business. Topics covered include product design, piloting, identifying customers, sales and marketing, business models, capital raising and more.\' category_name=\'resources\' posts_per_page= 6]\n<!-- /wp:shortcode -->', 'LaunchPad', '', 'inherit', 'closed', 'closed', '', '63-revision-v1', '', '', '2026-03-25 04:18:26', '2026-03-25 04:18:26', '', 63, 'http://localhost/tienThemes3/?p=319', 0, 'revision', '', 0),
