(418, 1, '2026-03-26 16:53:30', '2026-03-26 09:53:30', '<!-- wp:paragraph -->\n<p><strong>The Australian Publishers Association (APA) is the national representative body for the Australian publishing industry.</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We champion the interests of Australian publishers, support industry development and learning, and promote the value of books and reading to Australian society.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Our purpose is to make the business of publishing easier – delivering key programs, initiatives and advocacy work on behalf of our members to enhance and enrich the sector.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We represent and advance the industry through our advocacy work, building trusted relationships with politicians, government bodies and key industry stakeholders.</p>\n<!-- /wp:paragraph -->', 'Australian Publishers Association', '', 'publish', 'closed', 'closed', '', 'australian-publishers-association', '', '', '2026-03-27 09:14:51', '2026-03-27 02:14:51', '', 0, 'http://localhost/tienThemes3/?post_type=partner&#038;p=418', 0, 'partner', '', 0),
